import java.io.*;
public class Cloning {
    static class Box implements Serializable {
        int value;
        Box(int v) { this.value = v; }
    }

    // Deep copy via serialization
    @SuppressWarnings("unchecked")
    static <T extends Serializable> T deepCopy(T obj) throws Exception {
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        new ObjectOutputStream(bos).writeObject(obj);
        return (T) new ObjectInputStream(new ByteArrayInputStream(bos.toByteArray())).readObject();
    }

    public static void main(String[] args) throws Exception {
        Box original = new Box(42);
        Box copy = deepCopy(original);
        copy.value = 99;
        System.out.println(original.value);
        System.out.println(copy.value);
        System.out.println(original == copy);
    }
}
